// // This module implements a D flip-flop with an AND gate as its input source. The AND gate receives inputs 'w', 'x', 'y', and 'z'. The flip-flop is triggered on the falling edge of 'clk' and has an active-low synchronous reset 'rst'. When reset is active, the flip-flop output should be '0'.
module top_module (
	input clk,
	input rst,
	input w,
	input x,
	input y,
	input z,
	output reg out);

	initial
		out = 0;

	always@(posedge clk) begin
		if (rst)
			out <= 1;
		else
			out <= w & x & y & z;
	end

endmodule
